/// Services collection for all CRUD endpoints
pub struct HttpServices {
    pub tax_category: Arc<TaxCategoryService>,
    pub tax_template: Arc<TaxTemplateService>,
    pub tax_template_row: Arc<TaxTemplateRowService>,
    pub withholding_category: Arc<WithholdingCategoryService>,
}

/// Configure all HTTP routes for this module using Axum and BackboneCrudHandler.
///
/// Each entity gets 12 standard Backbone CRUD endpoints:
/// 1. GET /api/v1/{collection} - List with pagination
/// 2. POST /api/v1/{collection} - Create
/// 3. GET /api/v1/{collection}/:id - Get by ID
/// 4. PUT /api/v1/{collection}/:id - Full update
/// 5. PATCH /api/v1/{collection}/:id - Partial update
/// 6. DELETE /api/v1/{collection}/:id - Soft delete
/// 7. POST /api/v1/{collection}/bulk - Bulk create
/// 8. POST /api/v1/{collection}/upsert - Upsert
/// 9. GET /api/v1/{collection}/trash - List deleted
/// 10. POST /api/v1/{collection}/:id/restore - Restore
/// 11. DELETE /api/v1/{collection}/empty - Empty trash
/// 12. GET /api/v1/{collection}/:id/deleted - Get deleted by ID
pub fn configure_routes(services: HttpServices) -> Router {
    Router::new()
        // TaxCategory routes (12 Backbone endpoints)
        .merge(create_tax_category_routes(services.tax_category))
        // TaxTemplate routes (12 Backbone endpoints)
        .merge(create_tax_template_routes(services.tax_template))
        // TaxTemplateRow routes (12 Backbone endpoints)
        .merge(create_tax_template_row_routes(services.tax_template_row))
        // WithholdingCategory routes (12 Backbone endpoints)
        .merge(create_withholding_category_routes(services.withholding_category))
}

/// Create an individual entity's routes (for modular configuration)
